def _measure_emotional_intensity(text):
    # Simple heuristic for emotional intensity
    emotional_markers = ['very', 'extremely', 'deeply', '!!!', '???']
    intensity_score = sum(text.lower().count(marker) for marker in emotional_markers)
    return min(max(intensity_score, 0), 10)

def _determine_emotional_valence(text):
    # Basic sentiment polarity detection
    positive_words = ['happy', 'good', 'great', 'love', 'wonderful']
    negative_words = ['sad', 'bad', 'terrible', 'hate', 'awful']
    
    positive_count = sum(text.lower().count(word) for word in positive_words)
    negative_count = sum(text.lower().count(word) for word in negative_words)
    
    return (positive_count - negative_count) / (positive_count + negative_count + 1)

